        return jsonEncodingFailed.fromMap(map);
      case 'customEncodingFailed':
        return customEncodingFailed.fromMap(map);
      case 'url':
        return url.fromMap(map);
      case 'httpMethod':
        return httpMethod.fromMap(map);
